var d = msg.payload;
if (typeof d === 'string') {
    try { d = JSON.parse(d); } catch(e) { node.error('JSON invalido'); return null; }
}

// Mapeia campo 'status' do sketch para os campos esperados pelo Node-RED
var statusMap = {
    'IDEAL':    { condicao: 'Condições ideais para plantação',  boa: true,  cod: 'IDEAL'    },
    'GEADA':    { condicao: 'Risco de geada!',                  boa: false, cod: 'GEADA'    },
    'CALOR':    { condicao: 'Calor excessivo!',                 boa: false, cod: 'CALOR'    },
    'SECA':     { condicao: 'Seca severa!',                     boa: false, cod: 'SECA'     },
    'ENCHARCA': { condicao: 'Encharcamento do solo!',           boa: false, cod: 'ENCHARCA' }
};
var st = statusMap[d.status] || { condicao: d.status || '---', boa: false, cod: d.status || '???' };
d.condicao        = st.condicao;
d.condicao_boa    = st.boa;
d.condicao_codigo = st.cod;

msg.payload = d;
msg.data    = d;
return msg;

var d = msg.payload;
if (typeof d === 'string') {
    try { d = JSON.parse(d); } catch(e) { return null; }
}
msg.payload = d;
msg.data    = d;
return msg;

var d = msg.payload;
if (typeof d === 'string') {
    try { d = JSON.parse(d); } catch(e) { return null; }
}
var ip     = d.ip        || '---';
var rssi   = d.rssi      || '---';
var uptime = d.uptime_s  || '---';
var ts     = d.timestamp || '';
msg.payload = '📡 Online | IP: ' + ip + ' | RSSI: ' + rssi + ' dBm | Uptime: ' + uptime + 's | ' + ts;
return msg;

var d = msg.data || msg.payload;
if (!d || typeof d !== 'object') return null;
var perIcon = (d.periodo === 'DIA') ? '☀️  DIA  (06h–17h59)' : '🌙  NOITE  (18h–05h59)';
return [
    { payload: d.temperatura },
    { payload: d.umidade },
    { payload: perIcon },
    { payload: d.temperatura, topic: 'Temperatura' },
    { payload: d.umidade,     topic: 'Umidade' },
    { payload: d.periodo === 'DIA' ? 1 : 0, topic: 'Período' },
    { data: d },
    { data: d },
    { data: d }
];

var d = msg.data;
if (!d) return null;
var cult = d.cultura      || '---';
var temp = d.temperatura;
var umid = d.umidade;
var per  = d.periodo      || '---';
var leit = d.leitura      || '-';
var cond = d.condicao     || '---';
var boa  = (d.condicao_boa === true);
var perIcon = (per === 'DIA') ? '☀️ DIA' : '🌙 NOITE';
var ico     = boa ? '✅' : '⚠️';
var faixas  = {
    'Soja':'20–30°C | 50–80%','Milho':'18–32°C | 50–75%',
    'Trigo':'10–25°C | 40–70%','Cana':'20–35°C | 60–85%',
    'Arroz':'20–35°C | 70–95%'
};
var ref = faixas[cult] ? '  [Ideal: ' + faixas[cult] + ']' : '';
msg.payload = ico + ' ' + cond + ref +
    '\nTemp: ' + temp + '°C  |  Umid: ' + umid + '%' +
    '  |  ' + perIcon + '  |  ' + cult + '  |  Leitura #' + leit;
return msg;

var d = msg.data;
if (!d) return null;
var cult    = d.cultura         || '---';
var per     = d.periodo         || '---';
var cod     = d.condicao_codigo || '---';
var leit    = d.leitura         || '-';
var ts      = d.timestamp       || '';
var perIcon = (per === 'DIA') ? '☀️ DIA' : '🌙 NOITE';
msg.payload = '🌾 ' + cult + '  |  ' + perIcon + '  |  Código: ' + cod + '  |  Leitura #' + leit + '  |  ' + ts;
return msg;

var d = msg.data;
if (!d) return null;
var cond    = d.condicao     || '---';
var boa     = (d.condicao_boa === true);
var cult    = d.cultura      || '---';
var per     = d.periodo      || '---';
var temp    = d.temperatura;
var umid    = d.umidade;
var perIcon = (per === 'DIA') ? '☀️' : '🌙';
var bg      = boa ? '#1a6e37' : '#a93226';
var ico     = boa ? '✅' : '🚨';
var titulo  = boa ? 'CONDIÇÃO BOA PARA PLANTAÇÃO' : 'CONDIÇÃO RUIM PARA PLANTAÇÃO';
msg.payload =
    '<div style="background:' + bg + ';color:#fff;padding:16px;border-radius:10px;text-align:center">' +
    '<div style="font-size:22px;font-weight:bold">' + ico + ' ' + titulo + '</div>' +
    '<div style="font-size:15px;margin:6px 0">' + cond + '</div>' +
    '<div style="font-size:13px;opacity:.85">' + cult + ' &nbsp;|&nbsp; ' + perIcon + ' ' + per +
    ' &nbsp;|&nbsp; ' + temp + '°C &nbsp;|&nbsp; ' + umid + '%</div>' +
    '</div>';
return msg;

var d = msg.data;
if (!d) return null;
var boa     = d.alerta_ativo === false;
var cond    = d.condicao     || '---';
var cult    = d.cultura      || '---';
var temp    = d.temperatura;
var umid    = d.umidade;
var per     = d.periodo      || '---';
var mot     = d.motivo       || '';
var leit    = d.leitura      || '-';
var ts      = d.timestamp    || '';
var perIcon = (per === 'DIA') ? '☀️ DIA' : '🌙 NOITE';
var ico     = boa ? '✅' : '🚨';
var linhas  = [
    ico + ' ' + cond,
    'Cultura: ' + cult + ' | ' + perIcon,
    'Temp: ' + temp + '°C | Umid: ' + umid + '%'
];
if (mot) linhas.push('Detalhe: ' + mot);
linhas.push('Leitura #' + leit + ' — ' + ts);
var texto = linhas.join('\n');
return [
    { payload: texto },
    (!boa) ? { payload: texto } : null
];
